#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X, K; scanf("%lld %lld %lld", &N, &X, &K);
        long long rB = X % K;
        long long rG = (N - X) % K;
        long long ans = llabs(rB - rG);
        printf("%lld\n", ans);
    }
    return 0;
}

