const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for(let t=0; t<T; t++){
  const N = BigInt(input[idx++]);
  const X = BigInt(input[idx++]);
  const K = BigInt(input[idx++]);
  const rB = X % K;
  const rG = (N - X) % K;
  const diff = rB > rG ? rB - rG : rG - rB;
  results.push(diff.toString());
}
console.log(results.join('\n'));
